import React, { useState, useEffect } from 'react'
import  { AppBar, Typography, Button, Toolbar, Avatar } from '@material-ui/core';
import { Link } from 'react-router-dom';
import { useDispatch } from 'react-redux';
import { useHistory } from 'react-router-dom';
import useStyles from './styles';
import instaJam from '../../images/instaJam.jpg';

const Navbar = () => {
    const classes = useStyles();
    const history = useHistory();
    const dispatch = useDispatch();
    const [user, setUser] = useState(JSON.parse(localStorage.getItem('profile')));

    // useEffect(() => {
    //     const token = user?.token;

    //     setUser(JSON.parse(localStorage.getItem('profile')));
    // }, [user?.token]);

    const logout = () => {
        dispatch({ type: 'LOGOUT'});
        history.push('/');
        setUser(null);
    };

  return (
    <AppBar className={classes.appBar} position='static' color='inherit'>
        <div className={classes.brandContainer}>
            <Typography component={Link} to='/' className={classes.heading} variant='h2' align='center'>instaJam</Typography>
            <img className={classes.image} src={instaJam} alt='instaJam' height='60'/>
        </div>
        <Toolbar className={classes.toolbar}>
            {
            user ? (
                <div className={classes.profile}>
                    <Avatar className={classes.purple} alt={user.result.name} src={user.result.imageUrl}>{user.result.name.charAt(0)}</Avatar>
                    <Typography className={classes.userName} variant='h6'>{user.result.name}</Typography>
                    <Button variant='contained' className={classes.logout} color='secondary' onClick={logout}>Logout</Button>
                </div>
            ) : (
                <Button component={Link} to='/auth' variant='contained' color='primary'>Sign in</Button>
            )}
        </Toolbar>
      </AppBar>
  )
}

export default Navbar;
